  ('social-worker-moex-07350', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於人力資源管理的描述，下列那一項是正確的？', '["人事管理以成員為主，強調成員在組織內如何發揮潛能；人力資源管理以組織為主，強調成員如何完 成組織的目標", "人事管理重視彈性；人力資源管理重視控制", "人事管理為作業取向，強調人事管理功能的發揮；人力資源管理為策略取向，強調人資管理與整體組 織的配合", "人事管理以員工組成招募小組，以甄選新進員工；人力資源管理由少數人負責員工招募"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
