  ('social-worker-moex-07354', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以下關於具有非營利特性的社會服務行銷，其與商業行銷的差異，何者正確？', '["商業行銷有行銷區隔；非營利行銷則沒有行銷區隔", "商業行銷與非營利行銷只有名稱上的差異，實質內容沒有差異", "商業行銷追求「利潤極大化」；非營利行銷追求「公益使命」的達成", "商業行銷可以計算行銷成本；非營利行銷沒有成本觀念"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
